package com.ecommerce.search;

import org.elasticsearch.action.admin.indices.create.CreateIndexRequest;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.support.master.AcknowledgedResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.index.query.RangeQueryBuilder;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.TermsAggregationBuilder;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.util.*;

@Service
public class ElasticsearchService {

    @Autowired
    private RestHighLevelClient client;

    @Value("${elasticsearch.index.name:products}")
    private String indexName;

    @PostConstruct
    public void createIndex() throws IOException {
        GetIndexRequest request = new GetIndexRequest(indexName);
        boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);
        
        if (!exists) {
            CreateIndexRequest createRequest = new CreateIndexRequest(indexName);
            createRequest.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 1)
                .put("index.refresh_interval", "30s")
            );
            
            createRequest.mapping(
                "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"name\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "    \"description\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "    \"price\": {\"type\": \"float\"},\n" +
                "    \"category\": {\"type\": \"keyword\"},\n" +
                "    \"brand\": {\"type\": \"keyword\"},\n" +
                "    \"tags\": {\"type\": \"keyword\"},\n" +
                "    \"inStock\": {\"type\": \"boolean\"},\n" +
                "    \"createdAt\": {\"type\": \"date\", \"format\": \"yyyy-MM-dd HH:mm:ss\"}\n" +
                "  }\n" +
                "}", XContentType.JSON);
            
            client.indices().create(createRequest, RequestOptions.DEFAULT);
        }
    }

    public void indexProduct(Product product) throws IOException {
        IndexRequest request = new IndexRequest(indexName);
        request.id(product.getId());
        request.source(product.toJson(), XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public void indexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        
        for (Product product : products) {
            IndexRequest request = new IndexRequest(indexName);
            request.id(product.getId());
            request.source(product.toJson(), XContentType.JSON);
            bulkRequest.add(request);
        }
        
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            throw new RuntimeException("Bulk indexing failed");
        }
    }

    public SearchResult searchProducts(SearchRequestDTO request) throws IOException {
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.from(request.getFrom());
        sourceBuilder.size(request.getSize());
        
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();
        
        if (request.getQuery() != null && !request.getQuery().isEmpty()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(request.getQuery(), "name", "description")
                .type("best_fields")
                .fuzziness("AUTO"));
        }
        
        if (request.getCategory() != null && !request.getCategory().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category", request.getCategory()));
        }
        
        if (request.getBrand() != null && !request.getBrand().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand", request.getBrand()));
        }
        
        if (request.getInStock() != null) {
            boolQuery.filter(QueryBuilders.termQuery("inStock", request.getInStock()));
        }
        
        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            RangeQueryBuilder priceRange = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                priceRange.gte(request.getMinPrice());
            }
            if (request.getMaxPrice() != null) {
                priceRange.lte(request.getMaxPrice());
            }
            boolQuery.filter(priceRange);
        }
        
        if (request.getTags() != null && !request.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", request.getTags()));
        }
        
        sourceBuilder.query(boolQuery);
        
        if (request.getSortBy() != null && !request.getSortBy().isEmpty()) {
            SortOrder order = request.getSortOrder() == null ? SortOrder.ASC : request.getSortOrder();
            sourceBuilder.sort(SortBuilders.fieldSort(request.getSortBy()).order(order));
        }
        
        TermsAggregationBuilder categoryAgg = AggregationBuilders.terms("categories")
            .field("category")
            .size(100);
            
        TermsAggregationBuilder brandAgg = AggregationBuilders.terms("brands")
            .field("brand")
            .size(100);
            
        TermsAggregationBuilder tagAgg = AggregationBuilders.terms("tags")
            .field("tags")
            .size(100);
            
        sourceBuilder.aggregation(categoryAgg);
        sourceBuilder.aggregation(brandAgg);
        sourceBuilder.aggregation(tagAgg);
        
        SearchRequest searchRequest = new SearchRequest(indexName);
        searchRequest.source(sourceBuilder);
        
        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);
        
        List<Product> products = new ArrayList<>();
        for (var hit : response.getHits()) {
            Product product = Product.fromJson(hit.getSourceAsString());
            products.add(product);
        }
        
        SearchResult result = new SearchResult();
        result.setProducts(products);
        result.setTotal(response.getHits().getTotalHits().value);
        result.setAggregations(extractAggregations(response));
        
        return result;
    }

    private Map<String, List<String>> extractAggregations(SearchResponse response) {
        Map<String, List<String>> aggregations = new HashMap<>();
        
        if (response.getAggregations() != null) {
            var categoryAgg = response.getAggregations().get("categories");
            List<String> categories = new ArrayList<>();
            categoryAgg.forEach(bucket -> categories.add(bucket.getKeyAsString()));
            aggregations.put("categories", categories);
            
            var brandAgg = response.getAggregations().get("brands");
            List<String> brands = new ArrayList<>();
            brandAgg.forEach(bucket -> brands.add(bucket.getKeyAsString()));
            aggregations.put("brands", brands);
            
            var tagAgg = response.getAggregations().get("tags");
            List<String> tags = new ArrayList<>();
            tagAgg.forEach(bucket -> tags.add(bucket.getKeyAsString()));
            aggregations.put("tags", tags);
        }
        
        return aggregations;
    }

    public void saveSearchQuery(String query, String userId) throws IOException {
        Map<String, Object> searchQuery = new HashMap<>();
        searchQuery.put("query", query);
        searchQuery.put("userId", userId);
        searchQuery.put("timestamp", new Date());
        
        IndexRequest request = new IndexRequest("search_queries");
        request.source(searchQuery, XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public void deleteIndex() throws IOException {
        DeleteIndexRequest request = new DeleteIndexRequest(indexName);
        AcknowledgedResponse response = client.indices().delete(request, RequestOptions.DEFAULT);
        if (!response.isAcknowledged()) {
            throw new RuntimeException("Index deletion failed");
        }
    }
}

@Service
public class ProductSearchService {
    
    @Autowired
    private ElasticsearchService elasticsearchService;
    
    public SearchResult searchProducts(SearchRequestDTO request) {
        try {
            return elasticsearchService.searchProducts(request);
        } catch (IOException e) {
            throw new RuntimeException("Search failed", e);
        }
    }
    
    public void indexProduct(Product product) {
        try {
            elasticsearchService.indexProduct(product);
        } catch (IOException e) {
            throw new RuntimeException("Product indexing failed", e);
        }
    }
    
    public void saveSearchQuery(String query, String userId) {
        try {
            elasticsearchService.saveSearchQuery(query, userId);
        } catch (IOException e) {
            throw new RuntimeException("Search query saving failed", e);
        }
    }
}

