@Component
public class Product {
    private String id;
    private String name;
    private String description;
    private Float price;
    private String category;
    private String brand;
    private List<String> tags;
    private Boolean inStock;
    private Date createdAt;
    
    public Product() {}
    
    public Product(String id, String name, String description, Float price, 
                   String category, String brand, List<String> tags, Boolean inStock) {
        this.id = id;
        this.name = name;
        this.description = description;
        this.price = price;
        this.category = category;
        this.brand = brand;
        this.tags = tags;
        this.inStock = inStock;
        this.createdAt = new Date();
    }
    
    public String getId() { return id; }
    public void setId(String id) { this.id = id; }
    
    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
    
    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }
    
    public Float getPrice() { return price; }
    public void setPrice(Float price) { this.price = price; }
    
    public String getCategory() { return category; }
    public void setCategory(String category) { this.category = category; }
    
    public String getBrand() { return brand; }
    public void setBrand(String brand) { this.brand = brand; }
    
    public List<String> getTags() { return tags; }
    public void setTags(List<String> tags) { this.tags = tags; }
    
    public Boolean getInStock() { return inStock; }
    public void setInStock(Boolean inStock) { this.inStock = inStock; }
    
    public Date getCreatedAt() { return createdAt; }
    public void setCreatedAt(Date createdAt) { this.createdAt = createdAt; }
    
    public String toJson() {
        return "{\n" +
            "\"id\": \"" + id + "\",\n" +
            "\"name\": \"" + name + "\",\n" +
            "\"description\": \"" + description + "\",\n" +
            "\"price\": " + price + ",\n" +
            "\"category\": \"" + category + "\",\n" +
            "\"brand\": \"" + brand + "\",\n" +
            "\"tags\": " + tags + ",\n" +
            "\"inStock\": " + inStock + ",\n" +
            "\"createdAt\": \"" + createdAt + "\"\n" +
            "}";
    }
    
    public static Product fromJson(String json) {
        // Simple JSON parsing - in production use proper JSON library
        Product product = new Product();
        product.setId(extractValue(json, "id"));
        product.setName(extractValue(json, "name"));
        product.setDescription(extractValue(json, "description"));
        product.setPrice(Float.valueOf(extractValue(json, "price")));
        product.setCategory(extractValue(json, "category"));
        product.setBrand(extractValue(json, "brand"));
        product.setInStock(Boolean.valueOf(extractValue(json, "inStock")));
        return product;
    }
    
    private static String extractValue(String json, String key) {
        int start = json.indexOf("\"" + key + "\": \"") + key.length() + 4;
        int end = json.indexOf("\"", start);
        return json.substring(start, end);
    }
}

